#include<bits/stdc++.h>

using namespace std;

typedef long long ll;

const int N=5e3+5,mod=1e9+9;

ll hs[N],f[N],invf[N];

int n;

char s[N];

int get_hs(int l,int r)

{

    return (hs[r]-hs[l-1]+mod)%mod*invf[l-1]%mod;

}

map<int,int>vis;

bool judge(int m)

{

    if(m==0) return true;

    vis.clear();

    for(int i=n-m+1;i>=1;i--)

        vis[get_hs(i,i+m-1)]++;

    int pos=1;

    for(int i=1;i<=n-m+1;i++)

    {

        while(pos<=i+m-1&&pos<=n-m+1)

        {

            vis[get_hs(pos,pos+m-1)]--;pos++;

        }

        if(pos>n-m+1) return false;

        if(vis[get_hs(i,i+m-1)]) return true;

    }

    return false;

}

ll qpow(ll a,ll n)

{

    ll ans=1;

    while(n)

    {

        if(n&1) ans=ans*a%mod;

        a=a*a%mod;

        n>>=1;

    }

    return ans;

}

int main()

{

    f[0]=invf[0]=1;

    for(int i=1;i<N;i++)

        f[i]=f[i-1]*13331%mod,invf[i]=qpow(f[i],mod-2);

    scanf("%d%s",&n,s+1);

    for(int i=1;i<=n;i++)

        hs[i]=(hs[i-1]+(s[i]-'a')*f[i])%mod;

    int l=0,r=n/2,ans;

    while(l<=r)

    {

        int m=l+r>>1;

        if(judge(m)) ans=m,l=m+1;

        else r=m-1;

    }

    printf("%d\n",ans);

}

