  for (int i = 1; i <= N; ++i) {

    for (int j = 1; j <= N; ++j) {

      if ((i == j) || (S[i] != S[j])) {

        dp[i][j] = 0;

      } else if (S[i] == S[j]) {

        dp[i][j] = std::min(dp[i-1][j-1] + 1, std::abs(i - j));

