struct mint {

    // Preparation: MOD is alrejady defined.

    ll value;

    mint(ll value = 0) : value((value % MOD + MOD) % MOD) {}

    mint pow(ll t) const {

        if (!t) return 1;

        mint a = pow(t >> 1);

        a *= a;

        if (t & 1) a *= *this;

        return a;

    }

    mint pow(mint m) const {

        return pow(m.value);

    }

    mint inv() const {

        ll a = value, b = MOD, u = 1, v = 0;

        while (b) {

            ll t = a / b;

            a -= t * b;

            swap(a, b);

            u -= t * v;

            swap(u, v);

        }

        u %= MOD;

        return u;

    }

    mint &operator+=(const mint a) {

        if ((value += a.value) >= MOD) value -= MOD;

        return *this;

    }

    mint &operator-=(const mint a) {

        if ((value += MOD - a.value) >= MOD) value -= MOD;

        return *this;

    }

    mint &operator*=(const mint a) {

        (value *= a.value) %= MOD;

        return *this;

    }

    mint &operator/=(const mint a) {

        return (*this) *= a.inv();

    }

    mint operator+(const mint a) const {

        mint res(*this);

        return res += a;

    }

    mint operator-(const mint a) const {

        mint res(*this);

        return res -= a;

    }

    mint operator*(const mint a) const {

        mint res(*this);

        return res *= a;

    }

    mint operator/(const mint a) const {

        mint res(*this);

        return res /= a;

    }

};

